use std::collections::HashMap;

pub type Example = HashMap<String, String>;

#[derive(Default)]
#[allow(dead_code)]
pub struct World {
    pub binary_path: Option<String>,
    pub exit_code: Option<i32>,
    pub stdout: Option<String>,
    pub stderr: Option<String>,
    pub exit_code2: Option<i32>,
    pub stdout2: Option<String>,
}

impl World {
    pub fn new() -> Self {
        Self::default()
    }

    #[allow(dead_code)]
    pub fn require_stdout(&self) -> Result<&str, StepResult> {
        self.stdout
            .as_deref()
            .ok_or_else(|| StepResult::fail("stdout not yet recorded"))
    }

    #[allow(dead_code)]
    pub fn require_stderr(&self) -> Result<&str, StepResult> {
        self.stderr
            .as_deref()
            .ok_or_else(|| StepResult::fail("stderr not yet recorded"))
    }
}

pub struct StepResult {
    pub success: bool,
    pub message: String,
}

impl StepResult {
    pub fn ok() -> Self {
        StepResult { success: true, message: String::new() }
    }
    pub fn fail(msg: impl Into<String>) -> Self {
        StepResult { success: false, message: msg.into() }
    }
}

