5	thread_local! {
6	    pub static FIXTURE_DIR: RefCell<Option<tempfile::TempDir>> = const { RefCell::new(None) };
7	    pub static FIXTURE_ROOT: RefCell<Option<String>> = const { RefCell::new(None) };
