14	pub fn ensure_fixture_dir() -> Result<String, StepResult> {
15	    FIXTURE_DIR.with(|dir| {
16	        let mut borrow = dir.borrow_mut();
17	        if borrow.is_none() {
18	            match tempfile::TempDir::new() {
19	                Ok(td) => {
20	                    let path = td.path().to_string_lossy().to_string();
21	                    *borrow = Some(td);
22	                    FIXTURE_ROOT.with(|r| *r.borrow_mut() = Some(path));
23	                }
24	                Err(e) => {
25	                    return Err(StepResult::fail(format!("failed to create temp dir: {}", e)));
26	                }
27	            }
28	        }
29	        Ok(FIXTURE_ROOT.with(|r| r.borrow().clone().unwrap()))
30	    })
31	}
