33	pub fn write_fixture(root: &str, relative: &str, content: &str) -> Result<(), StepResult> {
34	    let full = Path::new(root).join(relative);
35	    if let Some(parent) = full.parent() {
36	        std::fs::create_dir_all(parent)
37	            .map_err(|e| StepResult::fail(format!("mkdir {}: {}", parent.display(), e)))?;
38	    }
39	    std::fs::write(&full, content)
40	        .map_err(|e| StepResult::fail(format!("write {}: {}", full.display(), e)))?;
