44	pub fn accumulate_sum_source(params: &str) -> String {
45	    let ids: Vec<&str> = params.split(',').collect();
46	    let (p0, p1, p2) = if ids.len() >= 3 {
47	        (ids[0].trim(), ids[1].trim(), ids[2].trim())
48	    } else {
