52	        "pub fn accumulate_sum({p0}: i32, {p1}: i32) -> i32 {{\n    let {p2} = {p0} + {p1};\n    let extra = {p2} * 2;\n    let more = extra + {p0};\n    let result = more + {p1};\n    result\n}}\n",
