65	pub fn step_then_exit_code(step: &str, world: &mut crate::runtime::World) -> Option<StepResult> {
66	    static RE: std::sync::OnceLock<regex::Regex> = std::sync::OnceLock::new();
67	    let re = RE.get_or_init(|| regex::Regex::new(r#"^the exit code is "?(\d+)"?$"#).unwrap());
68	    let caps = re.captures(step)?;
69	    let expected: i32 = caps.get(1).unwrap().as_str().parse().unwrap();
70	    let actual = match world.exit_code {
71	        Some(c) => c,
72	        None => return Some(StepResult::fail("exit code not yet recorded")),
73	    };
74	    Some(if actual == expected {
75	        StepResult::ok()
76	    } else {
77	        let stderr = world.require_stderr().unwrap_or("");
78	        let stdout = world.require_stdout().unwrap_or("");
79	        StepResult::fail(format!(
80	            "expected exit code {}, got {}\nstdout: {}\nstderr: {}",
81	            expected, actual, stdout, stderr
