95	pub fn make_pair(a: &FunctionInfo, b: &FunctionInfo, score: f64) -> DuplicatePair {
96	    let (left, right) = order_endpoints(a, b);
97	    DuplicatePair {
98	        score,
99	        left: PairEndpoint {
100	            file: left.file.clone(),
101	            start_line: left.start_line,
102	            end_line: left.end_line,
103	            nodes: left.node_hashes.len(),
104	        },
105	        right: PairEndpoint {
