34	    fn jaccard_bounds(
35	        a in prop::collection::vec(0u64..1000, 0..20),
36	        b in prop::collection::vec(0u64..1000, 0..20),
37	    ) {
38	        let score = jaccard(&a, &b);
39	        prop_assert!(score >= 0.0 && score <= 1.0);
40	    }
41	
42	    #[test]
43	    fn find_duplicate_pairs_sorted_descending(
44	        threshold in 0.0f64..=1.0,
45	        seed in 0u64..100,
46	    ) {
47	        let f1 = make_fn("a.rs", 1, 20, (seed..seed+15).collect());
48	        let f2 = make_fn("b.rs", 1, 20, (seed..seed+15).collect());
49	        let f3 = make_fn("c.rs", 1, 20, ((seed+50)..(seed+65)).collect());
50	        let f4 = make_fn("d.rs", 1, 20, ((seed+50)..(seed+65)).collect());
51	        let fns = vec![f1, f2, f3, f4];
52	        let pairs = find_duplicate_pairs(&fns, threshold, 1, 1);
53	        for window in pairs.windows(2) {
54	            prop_assert!(window[0].score >= window[1].score);
55	        }
56	    }
57	
58	    #[test]
59	    fn find_duplicate_pairs_no_self_pairs(
60	        start in 1usize..100,
61	        len in 5usize..20,
62	        threshold in 0.0f64..0.5,
63	    ) {
64	        let end = start + len;
65	        let hashes: Vec<u64> = (0..10).collect();
66	        let f = make_fn("a.rs", start, end, hashes);
